import * as React from "react";

export interface TdFooterColumn {
  title: string;
  links: { label: string; href: string }[];
}

export interface TdFooterSocial {
  label: string;
  href: string;
}

export interface TdFooterProps {
  brand: string;
  tagline?: string;
  columns: TdFooterColumn[];
  social?: TdFooterSocial[];
  legal: string;
  className?: string;
}

export function TdFooter({ brand, tagline, columns, social = [], legal, className = "" }: TdFooterProps) {
  return (
    <footer
      className={`w-full ${className}`.trim()}
      style={{ backgroundColor: "var(--td-primary, #2E6554)", color: "#ffffff" }}
    >
      <div className="mx-auto flex max-w-6xl flex-col gap-12 px-6 py-16">
        <div className="grid gap-10 md:grid-cols-[1.4fr_repeat(3,1fr)]">
          <div className="flex flex-col gap-3">
            <span className="text-xl font-semibold tracking-tight">{brand}</span>
            {tagline ? <p className="max-w-sm text-sm leading-relaxed text-white/75">{tagline}</p> : null}
          </div>
          {columns.map((col) => (
            <div key={col.title} className="flex flex-col gap-3">
              <h4 className="text-xs font-semibold uppercase tracking-[0.2em] text-white/70">{col.title}</h4>
              <ul className="flex flex-col gap-2">
                {col.links.map((link) => (
                  <li key={link.href}>
                    <a
                      href={link.href}
                      className="text-sm text-white/85 transition-colors hover:text-white"
                    >
                      {link.label}
                    </a>
                  </li>
                ))}
              </ul>
            </div>
          ))}
        </div>
        <div className="flex flex-col gap-4 border-t border-white/15 pt-6 text-sm text-white/70 md:flex-row md:items-center md:justify-between">
          <span>{legal}</span>
          {social.length > 0 ? (
            <ul className="flex flex-wrap gap-4">
              {social.map((s) => (
                <li key={s.href}>
                  <a href={s.href} className="transition-colors hover:text-white">
                    {s.label}
                  </a>
                </li>
              ))}
            </ul>
          ) : null}
        </div>
      </div>
    </footer>
  );
}

export default TdFooter;
